// Retrieve the incoming items
const items = $input.all().map(item => item.json);

// Helper function to safely grab a string from a field (handles Airtable arrays)
function getVal(val) {
  if (Array.isArray(val)) return val[0] || "";
  return val || "";
}

// 1. Group the output per PDEV Requirements
const groupedData = items.reduce((acc, item) => {
  const pdevReq = item["PDEV Requirements"] || "Unassigned";

  // LOGIC: Prioritize the new 'Assigned Process Engineer Name' (Array)
  // Fallback to legacy 'Process Engineer Name' (String) if the new one is empty
  const primaryEngineer = getVal(item["Assigned Process Engineer Name"]) || 
                          item["Process Engineer Name"] || 
                          "Unassigned";

  const insight = item["Dated Insights"] || item["Insights"] || "No insight provided";

  // Initialize the group if it doesn't exist yet
  if (!acc[pdevReq]) {
    acc[pdevReq] = {
      pdevRequirement: pdevReq,
      assignedPE: primaryEngineer,
      insights: []
    };
  }

  // If we find the 'Assigned PE' in any record for this group, make sure it's the one we use
  if (primaryEngineer !== "Unassigned" && acc[pdevReq].assignedPE === "Unassigned") {
    acc[pdevReq].assignedPE = primaryEngineer;
  }

  // 2. Put the items into bullets
  acc[pdevReq].insights.push(`- ${insight}`);

  return acc;
}, {});

// 3. Put them into an LLM-ready structure
const llmReadyOutput = Object.values(groupedData).map(group => {

  // Create a clean Markdown block for the LLM context window
  // We emphasize the "Assigned PE" so the LLM knows exactly who to credit
  const markdownBlock = `### Requirement: ${group.pdevRequirement}
* **Assigned PE:** ${group.assignedPE}
* **Raw Insights for processing:**
${group.insights.join("\n")}`;

  return {
    json: {
      pdevRequirement: group.pdevRequirement,
      assignedPE: group.assignedPE,
      llmMarkdownContext: markdownBlock
    }
  };
});

return llmReadyOutput;

// 1. Get raw output and metadata from the Anthropic node
const firstItem = $input.first().json;

// DYNAMIC MODEL NAME: Converts technical IDs to friendly names
const rawModel = firstItem.model || "AI Model";
function getFriendlyModelName(id) {
  if (id.includes('haiku')) return "Haiku 4.5";
  if (id.includes('sonnet')) return "Sonnet 3.5";
  if (id.includes('mistral')) return "Mistral Large";
  if (id.includes('gpt-4o')) return "GPT-4o";
  return id; 
}
const modelName = getFriendlyModelName(rawModel);

// 2. Extract Token Usage
let totalTokens = 0;
if (firstItem.usage) {
  const input = firstItem.usage.input_tokens || 0;
  const output = firstItem.usage.output_tokens || 0;
  totalTokens = input + output;
}

// 3. Extract and Parse the JSON
let rawOutput = "";
if (firstItem.content && firstItem.content.length > 0) {
  rawOutput = firstItem.content[0].text || "[]";
} else {
  rawOutput = firstItem.text || "[]";
}

let summaryData = [];
try {
  const cleanedOutput = rawOutput.replace(/```json/gi, "").replace(/```/g, "").trim();
  summaryData = JSON.parse(cleanedOutput);
} catch (error) {
  return [{ json: { error: "Failed to parse JSON", rawOutput: rawOutput } }];
}

// 4. GROUPING LOGIC: Engineer -> Requirements
const engineerGroups = {};

for (const item of summaryData) {
  const engName = item.engineer || "Unassigned";
  const reqName = item.client || "General Activity";

  if (!engineerGroups[engName]) {
    engineerGroups[engName] = {};
  }

  if (!engineerGroups[engName][reqName]) {
    engineerGroups[engName][reqName] = [];
  }

  // Support multiple key names for bullet points
  const newBullets = item.insights || item.updates || item.bullets || [];
  engineerGroups[engName][reqName] = engineerGroups[engName][reqName].concat(newBullets);
}

// 5. Helper: Escape HTML
function escapeHtml(text) {
  return String(text || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

// 6. Build the HTML Blocks
let groupedHtml = "";
const sortedEngineers = Object.keys(engineerGroups).sort();

for (const eng of sortedEngineers) {
  let projectBlocks = "";
  const projects = Object.keys(engineerGroups[eng]).sort();

  for (const projName of projects) {
    const bullets = engineerGroups[eng][projName]
      .map(b => `<li>${escapeHtml(b)}</li>`)
      .join("");

    projectBlocks += `
      <div class="client-block">
        <div class="client-name">${escapeHtml(projName)}</div>
        <div class="client-insight">
          <ul>${bullets}</ul>
        </div>
      </div>
    `;
  }

  // Each Engineer gets their own section
  groupedHtml += `
    <div class="engineer-section">
      <div class="engineer-header">${escapeHtml(eng)}</div>
      ${projectBlocks}
    </div>
  `;
}

// 7. CSS Styles (Exact match to image colors and spacing)
const cssStyles = `
  <style>
    body { font-family: 'Segoe UI', Arial, sans-serif; background-color: #f4f7f6; padding: 20px; color: #333; }
    .card { background: #fff; border-radius: 8px; box-shadow: 0 4px 15px rgba(0,0,0,0.1); max-width: 850px; margin: 0 auto; overflow: hidden; }

    /* Main Header */
    .header { background-color: #e67e22; padding: 30px; text-align: center; }
    .header h1 { margin: 0; font-size: 26px; color: #fff; letter-spacing: 0.5px; }
    .header p { margin: 8px 0 0; color: #fff; opacity: 0.9; font-size: 15px; }

    .body { padding: 30px; }

    /* Engineer Section Box */
    .engineer-section { 
      margin-bottom: 25px; 
      padding: 20px; 
      border: 1px solid #e0e0e0; 
      border-radius: 12px; 
      background-color: #ffffff; 
    }

    /* Engineer Header */
    .engineer-header { 
      font-size: 20px; 
      font-weight: bold; 
      color: #e67e22; 
      margin-bottom: 15px; 
      border-bottom: 1px solid #eee; 
      padding-bottom: 10px; 
    }

    /* Requirement Block with Blue Accent */
    .client-block { 
      margin-bottom: 20px; 
      padding-left: 15px; 
      border-left: 4px solid #3498db; 
    }
    .client-block:last-child { margin-bottom: 5px; }

    .client-name { 
      font-weight: bold; 
      font-size: 16px; 
      color: #2c3e50; 
      margin-bottom: 8px; 
    }

    .client-insight ul { margin: 0; padding-left: 20px; font-size: 14px; color: #555; line-height: 1.6; }
    .client-insight li { margin-bottom: 6px; }

    .footer { padding: 15px; text-align: right; font-size: 10px; color: #95a5a6; border-top: 1px solid #eee; }
  </style>
`;

// 8. Final Output
return [{
  json: {
    html: `
      ${cssStyles}
      <div class="card">
        <div class="header">
          <h1>PDEV Daily Reporting</h1>
          <p>Summary of today's activity</p>
        </div>
        <div class="body">
          ${groupedHtml}
        </div>
        <div class="footer">
          Powered by ${modelName} | Total Tokens Used: ${totalTokens.toLocaleString()}
        </div>
      </div>
    `,
    total_tokens: totalTokens
  }
}];

// This takes the list of projects from the Aggregate node
const aggregatedArray = $json.llmMarkdownContext; 

// It "glues" them together with a double newline for the AI
return {
  llmMarkdownContext: aggregatedArray.join('\n\n')
};

